  ('police-f3743df6-moex-00360', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於行政程序委任代理人之敘述，下列何者錯誤？', '["每一當事人得委任三位代理人", "申請之撤回，須受特別授與代理權始得為之", "代理人於最初為行政程序行為時已確定者無須提出委任書", "代理權授與之撤回，經通知行政機關後，始對行政機關發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00361', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲某日收受乙機關對其所作成之非授予利益之行政處分，於下列何種情況下，該行政處分無效？', '["乙機關未給予甲陳述意見之機會", "乙機關承辦該事件之公務員應迴避而未迴避", "應以證書之方式作成而未給予證書", "該行政處分之內容違反法律保留原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00362', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲機關作成行政處分，核發乙一筆補助款後，始發現乙不符合請領之資格。下列有關行政機關追 回該補助款之敘述，何者正確？', '["甲機關不必考量相關情事，皆得撤銷原處分，請求乙返還", "甲機關之上級機關無權撤銷原處分", "甲機關應於知悉該處分違法後5年內撤銷原處分，請求乙返還", "甲機關於撤銷原處分後，欲請求乙返還時應以行政處分為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
