  ('police-f3743df6-moex-00364', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲向主管機關乙申請設廠之許可，若甲已大致符合法律所規定之設廠要件，僅欠缺一個要件時， 下列敘述何者錯誤？', '["乙得對甲為行政指導，輔導其如何符合該要件", "乙得對甲作成許可之處分，並附有工廠設備須向本國廠商購買之負擔", "乙得與甲簽訂行政契約，約定於甲符合該要件時，核發其許可", "乙得對甲作成許可之處分，並附有於甲符合該要件時，處分始生效力之條件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00365', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲依法向主管機關乙申請企業紓困貸款補助，於行政程序中甲申請閱覽卷宗，惟乙拒絕其閱覽。 甲對於乙拒絕之表示，不得單獨提起救濟之理由，下列敘述何者正確？', '["因該表示為行政程序中之處置", "因該表示為觀念通知", "因該表示未侵害甲之權利", "因甲無權申請閱覽卷宗"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
